import{_ as e,c as t,o as n,ae as r}from"./chunks/framework.BvcDoAct.js";const l=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/Management2/PART2/3.md","filePath":"zh-cn/Management2/PART2/3.md"}'),o={name:"zh-cn/Management2/PART2/3.md"};function s(p,a,i,c,A,S){return n(),t("div",null,[...a[0]||(a[0]=[r('<p>►2022/11</p><h2 id="be-first登上红白歌会的意义-以及aaa时期的体感" tabindex="-1">BE:FIRST登上红白歌会的意义，以及AAA时期的体感 <a class="header-anchor" href="#be-first登上红白歌会的意义-以及aaa时期的体感" aria-label="Permalink to &quot;BE:FIRST登上红白歌会的意义，以及AAA时期的体感&quot;">​</a></h2><p>#感知与实态 #势能加速 #愿景推动力 #红白歌会 #BE:FIRST</p><h3 id="在如今这个时代-谈-实态-和-实绩-需要的不只是数字" tabindex="-1">“在如今这个时代，谈‘实态’和‘实绩’，需要的不只是数字” <a class="header-anchor" href="#在如今这个时代-谈-实态-和-实绩-需要的不只是数字" aria-label="Permalink to &quot;“在如今这个时代，谈‘实态’和‘实绩’，需要的不只是数字”&quot;">​</a></h3><p><strong>BE:FIRST将在2022年12月31日首次登上《第73届NHK红白歌会》。成立仅3年的BMSG旗下、出道仅1年的组合能够登上这一国民级舞台，说其是“时代正在发生变化”的象征也不为过。作为曾以AAA成员身份7次登上红白的SKY-HI，他是如何看待“登上红白”的意义的呢？</strong></p><p>我认为，对于BE:FIRST来说，登上红白歌会，是一个难得的机会，可以让“已经很火的感觉”真正具备“现实支撑”。像AAA当年，其实是在没有“爆红体感”的情况下登上红白的，当时内心也多少会有“我们真的配站在这里吗”的不安。毕竟也没有特别突出的成绩。但即便如此，借由“登上红白”这一权威所赋予的“现实背书”，我能明显感受到外界风向开始改变。</p><p>人本身就有一种倾向——被告知“这个很火”，就会自然地向那里聚集。这就是所谓的“从众效应”。当年AAA正是因为登上红白，切实感受到了这种正向推动。</p><p>但BE:FIRST可能是反过来的情况。现在很幸运，很多人都会说“BE:FIRST现在很火”，单曲也有一定成绩，但那依然还停留在“感觉”层面。而我认为，现在这个时代，在衡量“实态”和“实绩”时，已经不仅仅是看数字了。红白歌会这种压倒性的权威，正好可以作为连接“感觉”与“实态”的桥梁，让BE:FIRST当前的良好势头进一步加速。</p><h3 id="只要呈现出足够好的内容-结果自然会跟上" tabindex="-1">只要呈现出足够好的内容，结果自然会跟上 <a class="header-anchor" href="#只要呈现出足够好的内容-结果自然会跟上" aria-label="Permalink to &quot;只要呈现出足够好的内容，结果自然会跟上&quot;">​</a></h3><p><strong>在红白名单公布之前的10月15日，NHK音乐节目《Venue101》的衍生特别节目《Venue101 Presents BE:FIRST LIVE SPECIAL》播出。而在节目播出前，SKY-HI也罕见地主动带动粉丝气氛。</strong></p><p>确实是有在“带节奏”，而且也挺少见的（笑）。我以前也经常说，从BMSG创立之初开始，我就一直在对音乐行业发出危机警示，所以也做好了可能会被行业方或所谓权威视为“对立面”的心理准备。但实际情况并不是这样，反而有很多人给予了超出预期的支持和善意反馈。在这样的背景下，我能很明确地感受到，《Venue101》团队是真心在支持整个BMSG。在这么多艺人活跃的情况下，红白最终选谁，本质上还是“他们想让谁上”。既然如此，我就会理解为——这档特别节目，也许是在给我们一个机会。那么，回应这份期待就变得非常重要。只要能呈现出足够好的内容，结果或许自然就会跟上。虽然（红白出场）从2022年初开始就是我们的目标，但这也是结合各种信息后形成的一种直觉判断。</p><p>在没有任何大资本背景的情况下，以个人身份创立公司两年、BE:FIRST出道一年，就能与这样的“权威”展开合作，这在以往的娱乐行业中几乎是不存在的事情。我认为这是非常具有历史意义的。这不仅会成为推动BMSG愿景前进的重要动力，也会进一步促进行业层面的变化。</p>',12)])])}const d=e(o,[["render",s]]);export{l as __pageData,d as default};
